 return <AppShell page={page} setPage={setPage} onLogout={async()=>{try{await api.logout()}finally{setUser(null)}}} user={user} onQuickCapture={()=>setQuickCaptureOpen(true)} onGlobalSearch={()=>setGlobalSearchOpen(true)} onShortcuts={()=>setShortcutsOpen(true)} navBadges={{tasks:{count:overdueTaskCount+pendingApprovalTotal,label:pendingApprovalTotal&&!overdueTaskCount?'승인 대기':'지연'},today:{count:pendingTodoCount,label:'할 일'},calendar:{count:conflictEventCount,label:'충돌'}}}>{dataError?<div className="data-error" role="alert"><span>{dataError}</span><button onClick={refresh}>다시 시도</button></div>:null}<Suspense fallback={<ScreenFallback/>}>{screens[page]}</Suspense>
  {modal?.type==='task'?<Modal title={modal.task?'업무 수정':'새 업무'} onClose={()=>setModal(null)} isDirty={modalDirty}><TaskForm key={modal.task?.id ?? 'new-task'} task={modal.task} tasks={tasks} onDirtyChange={setModalDirty} onSave={async(data,applyToSeries)=>{try{const useSeries=applyToSeries&&modal.task?.recurrence_group_id;const savedTask=await (useSeries?api.updateTaskSeries(modal.task.recurrence_group_id,modal.task.due_date||modal.task.start_date,data):modal.task?api.updateTask(modal.task.id,data):api.createTask(data));try{await refreshTasksOnly();notify(useSeries?'이 업무와 이후 반복 업무를 모두 수정했습니다.':modal.task?'업무를 수정했습니다.':'업무를 추가했습니다.')}catch(e){if(!useSeries)mergeSavedTask(savedTask);notify('업무는 저장했지만 목록을 다시 불러오지 못했습니다. 잠시 후 다시 확인해 주세요.','error')}setModal(null);return {ok:true,error:''}}catch(e){notify(e.message,'error');return {ok:false,error:e.message}}}} onDelete={modal.task?()=>{const subtasks=subtaskCompletionSummary(tasks,modal.task.id);const groupId=modal.task.recurrence_group_id;return askDelete(<>{`'${modal.task.title}' 업무를 삭제합니다.${subtasks?` 하위 업무 ${subtasks.total}개는 최상위 업무로 이동됩니다.`:''}`}{groupId?<label className="span-2"><input type="checkbox" ref={el=>deleteSeriesRef.current=el}/> <span>이 업무와 이후 반복 업무에 모두 적용</span></label>:null}</>,async()=>{const useSeries=groupId&&deleteSeriesRef.current?.checked;if(useSeries)await api.deleteTaskSeries(groupId,modal.task.due_date||modal.task.start_date);else await api.deleteTask(modal.task.id);setModal(null)},'업무를 삭제했습니다.',groupId?undefined:undoDelete('tasks',modal.task.id))}:null} onCancel={()=>setModal(null)}/></Modal>:null}
  {taskLogsModal?<Modal title={`${taskLogsModal.task.title} 관련 업무 기록`} onClose={()=>setTaskLogsModal(null)}>{taskLogsModal.loading?<p>불러오는 중...</p>:<><form className="quick-entry" onSubmit={e=>{e.preventDefault();addTaskLog()}}><div className="quick-add"><input value={taskLogDraft.content} onChange={e=>setTaskLogDraft(d=>({...d,content:e.target.value}))} aria-label="업무 기록 내용" placeholder="이 업무에 대한 기록 추가"/><input className="log-minutes" type="number" min="0" max="1440" value={taskLogDraft.duration} onChange={e=>setTaskLogDraft(d=>({...d,duration:e.target.value}))} aria-label="소요 시간(분)" placeholder="분"/><button disabled={!taskLogDraft.content.trim()}>기록</button></div></form>{taskLogsModal.logs.length?<><p className="muted">총 {formatDuration(taskWorkLogsTotalMinutes(taskLogsModal.logs))} 기록됨 · {taskLogsModal.logs.length}건</p>{(()=>{const overrun=taskEstimateOverrun(taskLogsModal.task.estimated_minutes,taskWorkLogsTotalMinutes(taskLogsModal.logs));return overrun?<p className={overrun.isOver?'task-estimate-overrun':'muted'}>예상 {formatDuration(taskLogsModal.task.estimated_minutes)} 대비 {overrun.isOver?`${formatDuration(overrun.overMinutes)} 초과`:`${formatDuration(-overrun.overMinutes)} 여유`}</p>:null})()}<ul className="task-log-list">{taskLogsModal.logs.map(log=><li key={log.id}><strong>{log.log_date}</strong><span>{log.content}</span>{log.duration_minutes?<small>{formatDuration(log.duration_minutes)}</small>:null}</li>)}</ul></>:<p className="empty">연결된 업무 기록이 없습니다.</p>}</>}</Modal>:null}
  {confirm?<ConfirmDialog message={confirm.message} busy={confirm.busy} onClose={()=>setConfirm(null)} onConfirm={runDelete}/>:null}<QuickCapture open={quickCaptureOpen} onClose={()=>setQuickCaptureOpen(false)} notify={notify} onApplied={refresh} data={{tasks,events,todos,work_logs:logs}} onNavigate={setPage}/>{shortcutsOpen?<Modal title="단축키 안내" onClose={()=>setShortcutsOpen(false)}><KeyboardShortcuts/></Modal>:null}<GlobalSearch open={globalSearchOpen} onClose={()=>setGlobalSearchOpen(false)} data={{tasks,events,todos:allTodos,logs}} onOpenTask={task=>setModal({type:'task',task})} onOpenTodo={todo=>{setPage('today');setTodoFocus(todo.id)}} onOpenLog={log=>{setPage('today');setLogFocus(log.id)}} onOpenEvent={event=>{setPage('calendar');setEventFocus(event.id)}}/><Toast toast={toast} onClose={()=>{toastRef.current=null;setToast(null)}}/></AppShell>
